// Example MCP client config (remote / Streamable HTTP)
{
  "mcpServers": {
    "openarx": {
      "url": "https://mcp.openarx.ai/researcher/mcp"
      // auth: bearer token from portal.openarx.ai
    }
  }
}

{
  "mcpServers": {
    "biel-ai": {
      "description": "Query your product's documentation, APIs, and knowledge base.",
      "command": "npx",
      "args": [
        "mcp-remote",
        "https://mcp.biel.ai/sse?project_slug=YOUR_PROJECT_SLUG&domain=https://your-docs-domain.com"
      ]
    }
  }
}
